+using Microsoft.EntityFrameworkCore;
+
+public class LicenseVerificationService
+{
+    private readonly AppDbContext _context;
+
+    public LicenseVerificationService(AppDbContext context)
+    {
+        _context = context;
+    }
+
+    public async Task<LicenseStatus> GetLicenseStatusAsync(
+        int providerId,
+        string stateCode,
+        CancellationToken cancellationToken = default)
+    {
+        var license = await _context.Licenses
+            .AsNoTracking()
+            .Where(l => l.ProviderId == providerId && l.StateCode == stateCode)
+            .Select(l => new LicenseStatus
+            {
+                IsActive = l.ExpirationDate > DateTime.UtcNow,
+                ExpirationDate = l.ExpirationDate,
+                LicenseNumber = l.LicenseNumber
+            })
+            .FirstOrDefaultAsync(cancellationToken);
+
+        return license ?? LicenseStatus.NotFound;
+    }
+}
